from __future__ import annotations

import argparse
import hashlib
import os
import re
import sys
from collections import deque
from pathlib import Path
from typing import Iterable
from urllib.parse import urldefrag, urljoin, urlparse

import requests
from bs4 import BeautifulSoup


IMAGE_EXTENSIONS = {
    ".jpg",
    ".jpeg",
    ".png",
    ".gif",
    ".webp",
    ".bmp",
    ".svg",
    ".avif",
}

DEFAULT_HEADERS = {
    "User-Agent": (
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
        "AppleWebKit/537.36 (KHTML, like Gecko) "
        "Chrome/124.0 Safari/537.36"
    )
}


def normalize_url(url: str, base_url: str | None = None) -> str | None:
    if base_url:
        url = urljoin(base_url, url)
    url, _fragment = urldefrag(url)
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        return None
    return url


def same_site(url: str, root_netloc: str) -> bool:
    return urlparse(url).netloc.lower() == root_netloc.lower()


def parse_srcset(srcset: str) -> Iterable[str]:
    for item in srcset.split(","):
        candidate = item.strip().split(" ", 1)[0].strip()
        if candidate:
            yield candidate


def image_urls_from_page(html: str, page_url: str) -> set[str]:
    soup = BeautifulSoup(html, "html.parser")
    urls: set[str] = set()

    for tag in soup.find_all(["img", "source"]):
        for attr in ("src", "data-src", "data-original", "data-lazy-src"):
            value = tag.get(attr)
            if value:
                normalized = normalize_url(value, page_url)
                if normalized:
                    urls.add(normalized)

        srcset = tag.get("srcset")
        if srcset:
            for value in parse_srcset(srcset):
                normalized = normalize_url(value, page_url)
                if normalized:
                    urls.add(normalized)

    for tag in soup.find_all("meta"):
        if tag.get("property") in {"og:image", "twitter:image"}:
            value = tag.get("content")
            if value:
                normalized = normalize_url(value, page_url)
                if normalized:
                    urls.add(normalized)

    return urls


def page_links_from_page(html: str, page_url: str, root_netloc: str) -> set[str]:
    soup = BeautifulSoup(html, "html.parser")
    links: set[str] = set()
    for tag in soup.find_all("a", href=True):
        normalized = normalize_url(tag["href"], page_url)
        if normalized and same_site(normalized, root_netloc):
            links.add(normalized)
    return links


def extension_from_response(url: str, content_type: str | None) -> str:
    suffix = Path(urlparse(url).path).suffix.lower()
    if suffix in IMAGE_EXTENSIONS:
        return suffix

    if content_type:
        media_type = content_type.split(";", 1)[0].strip().lower()
        mapping = {
            "image/jpeg": ".jpg",
            "image/png": ".png",
            "image/gif": ".gif",
            "image/webp": ".webp",
            "image/bmp": ".bmp",
            "image/svg+xml": ".svg",
            "image/avif": ".avif",
        }
        if media_type in mapping:
            return mapping[media_type]

    return ".img"


def safe_filename(url: str, extension: str) -> str:
    parsed = urlparse(url)
    name = Path(parsed.path).stem
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", name).strip("._-")
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()[:10]
    if not name:
        name = "image"
    return f"{name}_{digest}{extension}"


def download_image(
    session: requests.Session,
    image_url: str,
    output_dir: Path,
    timeout: int,
) -> Path | None:
    try:
        with session.get(image_url, stream=True, timeout=timeout) as response:
            response.raise_for_status()
            content_type = response.headers.get("content-type", "")
            if not content_type.lower().startswith("image/"):
                print(f"skip non-image: {image_url}")
                return None

            extension = extension_from_response(image_url, content_type)
            filename = safe_filename(image_url, extension)
            target = output_dir / filename

            with target.open("wb") as file:
                for chunk in response.iter_content(chunk_size=1024 * 64):
                    if chunk:
                        file.write(chunk)

            print(f"downloaded: {target}")
            return target
    except requests.RequestException as exc:
        print(f"failed image: {image_url} ({exc})")
        return None


def crawl(args: argparse.Namespace) -> int:
    start_url = normalize_url(args.url)
    if not start_url:
        print("Invalid URL. Use a full http:// or https:// URL.", file=sys.stderr)
        return 2

    root_netloc = urlparse(start_url).netloc
    output_dir = Path(args.output).resolve()
    output_dir.mkdir(parents=True, exist_ok=True)

    session = requests.Session()
    session.headers.update(DEFAULT_HEADERS)

    queue: deque[tuple[str, int]] = deque([(start_url, 0)])
    visited_pages: set[str] = set()
    seen_images: set[str] = set()
    downloaded = 0

    while queue and len(visited_pages) < args.max_pages and downloaded < args.max_images:
        page_url, depth = queue.popleft()
        if page_url in visited_pages:
            continue
        visited_pages.add(page_url)

        try:
            response = session.get(page_url, timeout=args.timeout)
            response.raise_for_status()
        except requests.RequestException as exc:
            print(f"failed page: {page_url} ({exc})")
            continue

        content_type = response.headers.get("content-type", "").lower()
        if "text/html" not in content_type:
            continue

        print(f"scan page: {page_url}")
        html = response.text

        for image_url in image_urls_from_page(html, page_url):
            if downloaded >= args.max_images:
                break
            if image_url in seen_images:
                continue
            seen_images.add(image_url)
            if download_image(session, image_url, output_dir, args.timeout):
                downloaded += 1

        if depth < args.max_depth:
            for link in page_links_from_page(html, page_url, root_netloc):
                if link not in visited_pages:
                    queue.append((link, depth + 1))

    print(
