class LinkImageParser(HTMLParser):
    def __init__(self, page_url: str) -> None:
        super().__init__(convert_charrefs=True)
        self.page_url = page_url
        self.links: set[str] = set()
        self.images: set[str] = set()

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        data = {key.lower(): value for key, value in attrs if value}
        tag = tag.lower()

        if tag == "a" and data.get("href"):
            normalized = normalize_url(data["href"], self.page_url)
            if normalized:
                self.links.add(normalized)

        if tag in {"img", "source"}:
            for attr in ("src", "data-src", "data-original", "data-lazy-src"):
                if data.get(attr):
                    normalized = normalize_url(data[attr], self.page_url)
                    if normalized:
                        self.images.add(normalized)

            if data.get("srcset"):
                for value in parse_srcset(data["srcset"]):
                    normalized = normalize_url(value, self.page_url)
                    if normalized:
                        self.images.add(normalized)

        if tag == "meta" and data.get("property") in {"og:image", "twitter:image"}:
            if data.get("content"):
                normalized = normalize_url(data["content"], self.page_url)
                if normalized:
                    self.images.add(normalized)


def normalize_url(url: str, base_url: str | None = None) -> str | None:
    if base_url:
        url = urljoin(base_url, url)
    url, _fragment = urldefrag(url)
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        return None
    return url


def same_site(url: str, root_netloc: str) -> bool:
    return urlparse(url).netloc.lower() == root_netloc.lower()


def parse_srcset(srcset: str) -> Iterable[str]:
    for item in srcset.split(","):
        candidate = item.strip().split(" ", 1)[0].strip()
        if candidate:
            yield candidate


def parse_page(html: str, page_url: str) -> LinkImageParser:
    parser = LinkImageParser(page_url)
    parser.feed(html)
    return parser


def extension_from_response(url: str, content_type: str | None) -> str:
