    if not name:
        name = "image"
    if prefix:
        return f"{prefix}_{name}_{digest}{extension}"
    return f"{name}_{digest}{extension}"


def open_url(opener, url: str, timeout: int, referer: str | None = None):
    headers = dict(DEFAULT_HEADERS)
    if referer:
        headers["Referer"] = referer
    request = Request(url, headers=headers)
    return opener.open(request, timeout=timeout)


def read_text_page(opener, page_url: str, timeout: int) -> str | None:
    try:
        with open_url(opener, page_url, timeout) as response:
            content_type = response.headers.get("content-type", "").lower()
            if "text/html" not in content_type:
                return None
            charset = response.headers.get_content_charset() or "utf-8"
            return response.read().decode(charset, errors="replace")
    except (HTTPError, URLError, TimeoutError, OSError) as exc:
        print(f"failed page: {page_url} ({exc})")
        return None


def download_image(
    opener,
    image_url: str,
    output_dir: Path,
    timeout: int,
    referer: str | None = None,
    prefix: str | None = None,
) -> Path | None:
    try:
        with open_url(opener, image_url, timeout, referer=referer) as response:
            content_type = response.headers.get("content-type", "")
            if not content_type.lower().startswith("image/"):
                print(f"skip non-image: {image_url}")
                return None

            extension = extension_from_response(image_url, content_type)
            filename = safe_filename(image_url, extension, prefix=prefix)
            target = output_dir / filename

            with target.open("wb") as file:
                while True:
                    chunk = response.read(1024 * 64)
                    if not chunk:
                        break
                    file.write(chunk)

            print(f"downloaded: {target}")
            return target
    except (HTTPError, URLError, TimeoutError, OSError) as exc:
        print(f"failed image: {image_url} ({exc})")
        return None


